def dedupe(rows):
    seen_emails = set()
    result = []
    for row in rows:
        if 'email' not in row:
            result.append(row)
        else:
            normalized = row['email'].strip().lower()
            if normalized not in seen_emails:
                seen_emails.add(normalized)
                result.append(row)
    return result
```

