import re

_LOG_RE = re.compile(
    r'^(\S+)\s+-\s+\S+\s+\[([^\]]+)\]\s+"([^"]*)"\s+(\d{3})\s+(\S+)\s+"([^"]*)"\s+"([^"]*)"$'
)


def parse_line(line):
    m = _LOG_RE.match(line.strip())
    if m is None:
        return None

    ip, timestamp, request, status, bytes_sent, referrer, user_agent = m.groups()

    parts = request.split()
    if len(parts) == 3 and parts[2].startswith("HTTP/"):
        method, path = parts[0], parts[1]
    else:
        method = path = None

    if bytes_sent == "-":
        body_bytes = 0
    else:
        try:
            body_bytes = int(bytes_sent)
        except ValueError:
            return None

    return {
        "ip": ip,
        "timestamp": timestamp,
        "method": method,
        "path": path,
        "status": int(status),
        "bytes": body_bytes,
        "referrer": referrer,
        "user_agent": user_agent,
    }
